#include<bits/stdc++.h>
using namespace std;
int no[6];
int End=-1;
int main() {
	string b;
	cin>>b;
	if(b[0]!='M'||b[1]!='D'||b[2]!='A') {
		no[0]=no[1]=no[2]=no[3]=no[4]=no[5]=1;
	}
	if(no[5]==0) {
		for(int i=b.size()-1;i>=0;i--){
			if(isdigit(b[i])) {
				End=b[i]-'0';
				break;
			}
		}
		if(End!=0){
			no[min(End,10-End)]=1;
		}else{
			no[5]=1;
		}
		
	}
	cout<<no[1]<<" "<<no[2]<<" "<<no[3]<<" "<<no[4]<<" "<<no[5];
	return 0;
}
